172	 * Resolve the `--model` override passed to a spawned subagent.
173	 *
174	 * When no model is requested (`undefined`, `false`, empty, or the `"inherit"`
175	 * sentinel), the child must inherit the parent session's *in-memory* model
176	 * (`provider/id`) instead of being left to resolve its own model. Without an
177	 * explicit `provider/id`, the child falls back to the global
178	 * `~/.pi/agent/settings.json` default, which is shared across every open PI
179	 * session — so a different session that last changed its model in the TUI would
180	 * silently contaminate this session's subagents (see issue #266). Passing an
181	 * explicit `provider/id` keeps each session's children isolated to that
182	 * session's model.
183	 *
184	 * An explicitly requested model string is resolved via {@link resolveModelCandidate}.
185	 * When `options.scope.enforce` is on, an out-of-scope resolved model throws for
186	 * an explicit (`source: "explicit"`) request and warns for an inherited one.
187	 */
188	export function resolveSubagentModelOverride(
189		requestedModel: string | boolean | undefined,
190		parentModel: ParentModel | undefined,
191		availableModels: AvailableModelInfo[] | undefined,
192		preferredProvider?: string,
193		options?: ResolveSubagentModelOverrideOptions,
194	): string | undefined {
195		const trimmed = typeof requestedModel === "string" ? requestedModel.trim() : "";
196		const explicit = trimmed && trimmed !== INHERIT_MODEL ? trimmed : undefined;
197		let resolved: string | undefined;
198		if (explicit === undefined) {
199			resolved = parentModel ? `${parentModel.provider}/${parentModel.id}` : undefined;
200		} else {
201			resolved = resolveModelCandidate(explicit, availableModels, preferredProvider);
202		}
203		if (resolved && options?.scope?.enforce) {
204			const source: ModelSource = explicit === undefined ? "inherited" : (options.source ?? "inherited");
205			const violation = checkModelScope(resolved, options.scope, source);
206			if (violation) {
207				if (violation.severity === "error") throw new Error(violation.message);
208				(options.onWarn ?? defaultScopeWarn)(violation);
209			}
210		}
211		return resolved;
212	}
