221		primaryModel: string | undefined,
222		fallbackModels: string[] | undefined,
223		availableModels: AvailableModelInfo[] | undefined,
224		preferredProvider?: string,
225		options?: BuildModelCandidatesOptions,
226	): string[] {
227		const seen = new Set<string>();
228		const candidates: string[] = [];
229		const rawCandidates = [primaryModel, ...(fallbackModels ?? [])];
230		for (let index = 0; index < rawCandidates.length; index++) {
231			const raw = rawCandidates[index];
232			if (!raw) continue;
233			const normalized = resolveModelCandidate(raw.trim(), availableModels, preferredProvider);
234			if (!normalized || seen.has(normalized)) continue;
