236				const violation = checkModelScope(normalized, options.scope, "inherited");
237				if (violation) (options.onWarn ?? defaultScopeWarn)(violation);
238			}
239			seen.add(normalized);
240			candidates.push(normalized);
241		}
242		return candidates;
243	}
