 701		if (!filePath) return EMPTY_SUBAGENT_SETTINGS;
 702		const settings = readSettingsFileStrict(filePath);
 703		const subagents = settings.subagents;
 704		if (!subagents || typeof subagents !== "object" || Array.isArray(subagents)) return EMPTY_SUBAGENT_SETTINGS;
 705	
 706		const subagentsObject = subagents as Record<string, unknown>;
 707		let disableBuiltins: boolean | undefined;
 708		if ("disableBuiltins" in subagentsObject) {
 709			if (typeof subagentsObject.disableBuiltins === "boolean") {
 710				disableBuiltins = subagentsObject.disableBuiltins;
 711			} else {
 712				throw new Error(`Subagent settings in '${filePath}' have invalid 'disableBuiltins'; expected a boolean.`);
 713			}
 714		}
 715		let disableThinking: boolean | undefined;
