 90	export function applyThinkingSuffix(model: string | undefined, thinking: string | false | undefined, replaceExisting = false): string | undefined {
 91		if (!model || !thinking) return model;
 92		const colonIdx = model.lastIndexOf(":");
 93		if (colonIdx !== -1 && THINKING_LEVELS.includes(model.substring(colonIdx + 1))) {
 94			return replaceExisting ? `${model.slice(0, colonIdx)}:${thinking}` : model;
 95		}
 96		return `${model}:${thinking}`;
 97	}
