 99	export function buildPiArgs(input: BuildPiArgsInput): BuildPiArgsResult {
100		const args = [...input.baseArgs];
101	
102		if (input.sessionFile) {
103			fs.mkdirSync(path.dirname(input.sessionFile), { recursive: true });
104			args.push("--session", input.sessionFile);
105		} else {
106			if (!input.sessionEnabled) {
107				args.push("--no-session");
108			}
109			if (input.sessionDir) {
110				fs.mkdirSync(input.sessionDir, { recursive: true });
111				args.push("--session-dir", input.sessionDir);
112			}
113		}
114	
115		const modelArg = applyThinkingSuffix(input.model, input.thinking);
116		if (modelArg) {
117			args.push("--model", modelArg);
118		}
119	
120		const declaredBuiltinToolsBase = input.tools?.filter((tool) => !(tool.includes("/") || tool.endsWith(".ts") || tool.endsWith(".js"))) ?? [];
121		const declaredBuiltinTools = input.requireReadTool && input.tools?.length && !declaredBuiltinToolsBase.includes("read")
122			? ["read", ...declaredBuiltinToolsBase]

